var eventName = "Evento sconosciuto";

switch (value) {
    case 0:
        eventName = "Nessun evento";
        break;
    case 1:
        eventName = "Apertura manuale";
        break;
    case 2:
        eventName = "Apertura remota";
        break;
    case 3:
        eventName = "Apertura per sovratensione";
        break;
    case 4:
        eventName = "Apertura per sottotensione";
        break;
    case 5:
        eventName = "Apertura per mancanza fase";
        break;
    case 6:
        eventName = "Apertura per sovraccarico";
        break;
    case 7:
        eventName = "Apertura per cortocircuito";
        break;
    case 8:
        eventName = "Apertura per sovrafrequenza";
        break;
    case 9:
        eventName = "Apertura per sottofrequenza";
        break;
    case 10:
        eventName = "Apertura per sovratemperatura";
        break;
    case 11:
        eventName = "Apertura per dispersione";
        break;
    case 12:
        eventName = "Scatto di prova da pulsante";
        break;
    case 13:
        eventName = "Scatto di prova remoto";
        break;
    case 100:
        eventName = "Chiusura manuale";
        break;
    case 101:
        eventName = "Chiusura remota";
        break;
    case 102:
        eventName = "Richiusura automatica";
        break;
    default:
        eventName = "Evento sconosciuto (" + value + ")";
}

return eventName;

